tests.methodBody:
LoginPage loginPage = new LoginPage(driver);
Assert.assertTrue(loginPage.isDisplayed(), "Login page should be displayed");
DashboardPage dashboard = loginPage.loginAs(config.validUsername(), config.validPassword());
Assert.assertTrue(dashboard.isLoaded(), "Dashboard should load after successful login");

LoginPage loginPage = new LoginPage(driver);
loginPage.enterUsername("");
loginPage.enterPassword(config.validPassword());
loginPage.clickLogin();
Assert.assertTrue(loginPage.isErrorDisplayed(), "Error should be displayed");
Assert.assertEquals(loginPage.getErrorMessage(), "Epic sadface: Username is required");

LoginPage loginPage = new LoginPage(driver);
loginPage.loginAs(config.validUsername(), TestUsers.INVALID_PASSWORD);
Assert.assertTrue(loginPage.isErrorDisplayed(), "Error should be displayed");
Assert.assertTrue(loginPage.getErrorMessage().contains("do not match any user"));
